#include <bits/stdc++.h>
using namespace std;

const int N=5010,mod=998244353;

inline int rd(){
    char ch=getchar();int r=0;
    while(ch<'0' || '9'<ch) ch=getchar();
    while('0'<=ch && ch<='9') r=(r<<3)+(r<<1)+ch-'0',ch=getchar();
    return r;
}

int c,T,n,h[N],tl[N],tr[N],s[N],cnt;
unsigned int f[N][N],sl[N][N],sr[N][N],g[N][N],ans[N],inv[N*3];
vector<int> e[N];

void init(){
    inv[0]=inv[1]=1;
    for(int i=2;i<N*3;i++)
        inv[i]=(unsigned long long)inv[mod%i]*(mod-mod/i)%mod;
}

void dfs(int x,int fa){
    h[x]=1;
    int sum=0;
    for(int i=0;i<e[x].size();i++){
        int y=e[x][i];
        if(y!=fa){
            dfs(y,x);
            h[x]=max(h[x],h[y]+1);
            sum+=h[y];
        }
    }
    cnt=0;
    for(int y:e[x])
        if(y!=fa)
            s[++cnt]=y;
    if(h[x]==1){
        f[x][1]=1;
        return;
    }
    //if(cnt==1){
    //    f[x][h[x]]=1;
    //    return;
    //}
    sl[0][0]=1;
    for(int i=1;i<=cnt;i++){
        tl[i]=tl[i-1]+h[s[i]];
        for(int j=0;j<=tl[i-1];j++)
            for(int k=1;k<=h[s[i]];k++)
                sl[i][j+k]=(sl[i][j+k]+(unsigned long long)sl[i-1][j]*f[s[i]][k])%mod;
    }
    sr[cnt+1][0]=1;
    for(int i=cnt;i;i--){
        tr[i]=tr[i+1]+h[s[i]];
        for(int j=0;j<=tr[i+1];j++)
            for(int k=1;k<=h[s[i]];k++)
                sr[i][j+k]=(sr[i][j+k]+(unsigned long long)sr[i+1][j]*f[s[i]][k])%mod;
    }
    /*
    for(int i=2;i<=h[x];i++)
        for(int v=1;v<=cnt;v++)
            for(int j=0;j<=sum;j++)
                for(int k=0;k<=sum;k++)
                    f[x][i]=(f[x][i]+1ll*sl[v-1][j]*sr[v+1][k]%mod*f[s[v]][i-1]%mod*(i-1)%mod*inv[i+j+k-1])%mod;
    for(int v=1;v<=cnt;v++)
        for(int i=1;i<=h[s[v]];i++)
            for(int j=0;j<=sum;j++)
                for(int k=0;k<=sum;k++)
                    ans[s[v]]=(ans[s[v]]+1ll*sl[v-1][j]*sr[v+1][k]%mod*f[s[v]][i]%mod*(j+k)%mod*inv[i+j+k]%mod)%mod;
    */
    for(int i=1;i<=cnt;i++)
        for(int j=0;j<=tl[i-1];j++)
            for(int k=0;k<=tr[i+1];k++)
                g[i][j+k]=(g[i][j+k]+(unsigned long long)sl[i-1][j]*sr[i+1][k])%mod;
    for(int v=1;v<=cnt;v++)
        for(int i=1;i<=h[s[v]];i++)
            for(int j=0;j<=sum-h[s[v]];j++){
                f[x][i+1]=(f[x][i+1]+(unsigned long long)g[v][j]*f[s[v]][i]%mod*i%mod*inv[i+j])%mod;
                ans[s[v]]=(ans[s[v]]+(unsigned long long)g[v][j]*f[s[v]][i]%mod*j%mod*inv[i+j])%mod;
            }
    for(int i=1;i<=cnt;i++){
        tl[i]=tr[i]=0;
        for(int j=0;j<=sum;j++)
            sl[i][j]=sr[i][j]=g[i][j]=0;
    }
    sl[0][0]=sr[cnt+1][0]=0;
}

void dfs2(int x,int fa){
    ans[x]=(ans[x]+ans[fa])%mod;
    for(int y:e[x])
        if(y!=fa)
            dfs2(y,x);
}

int main(){
    init();
    c=rd(),T=rd();
    while(T--){
        n=rd();
        for(int i=1;i<=n;i++)
            e[i].clear();
        for(int i=1,u,v;i<n;i++){
            u=rd(),v=rd();
            e[u].push_back(v);
            e[v].push_back(u);
        }
        for(int i=1;i<=n;i++){
            for(int j=1;j<=n;j++)
                f[i][j]=0;
            ans[i]=0;
        }
        dfs(1,0);
        dfs2(1,0);
        int res=0;
        for(int i=1;i<=n;i++){
            res=(res+ans[i])%mod;
            //for(int j=1;j<=n;j++)
            //    printf("%d ",f[i][j]);
            //printf("%d %d\n",h[i],ans[i]);
        }
        printf("%d\n",res);
    }
    return 0;
}
